Here are the authoritative public test cases for feature7_update_request:
{
  "description": "Serialize an update-service request into one flat string-keyed wire map. Unlike the start request, the update request does not carry channel-creation fields and its output is independent of the target platform. The request carries the notification content title and text, an optional icon, an optional ordered list of action buttons, an optional initial route, and an optional recurring-task scheduling configuration. The output emits the content title and text, the serialized icon object, the serialized buttons list, the initial route (null when absent), and finally the inlined task scheduling fields when a scheduling configuration is supplied. Colors render as comma-separated 'red,green,blue' strings and the task dispatch mode appears as its integer code.",
  "cases": [
    {
      "input": {
        "op": "update_request",
        "platform": "android",
        "taskOptions": {
          "event": {
            "type": "repeat",
            "interval": 1000
          },
          "autoRunOnBoot": true,
          "autoRunOnMyPackageReplaced": true,
          "allowWakeLock": true,
          "allowWifiLock": true
        },
        "contentTitle": "title",
        "contentText": "test",
        "icon": {
          "metaDataName": "test",
          "color": {
            "r": 255,
            "g": 152,
            "b": 0
          }
        },
        "buttons": [
          {
            "id": "id_test1",
            "text": "test1",
            "color": {
              "r": 156,
              "g": 39,
              "b": 176
            }
          },
          {
            "id": "id_test2",
            "text": "test2",
            "color": {
              "r": 76,
              "g": 175,
              "b": 80
            }
          }
        ]
      },
      "expected_output": "{\"notificationContentTitle\":\"title\",\"notificationContentText\":\"test\",\"icon\":{\"metaDataName\":\"test\",\"backgroundColorRgb\":\"255,152,0\"},\"buttons\":[{\"id\":\"id_test1\",\"text\":\"test1\",\"textColorRgb\":\"156,39,176\"},{\"id\":\"id_test2\",\"text\":\"test2\",\"textColorRgb\":\"76,175,80\"}],\"initialRoute\":null,\"taskEventAction\":{\"taskEventType\":3,\"taskEventInterval\":1000},\"autoRunOnBoot\":true,\"autoRunOnMyPackageReplaced\":true,\"allowWakeLock\":true,\"allowWifiLock\":true}\n"
    }
  ]
}

